def has_ayah_cue(left, right):
    # If there is a parenthetical citation like (something: number) within 80 chars right
    parenth_citation = bool(re.search(r'\([^)]+:\s*\d+\)', right[:80]))
    cue_in_left_or_right = any(cue in left[-80:] or cue in right[:80] for cue in ayah_cues)
    return parenth_citation or cue_in_left_or_right

def has_hadith_cue(left, right):
    return any(cue in left[-80:] or cue in right[:80] for cue in hadith_cues)

